const query = $input.first().json.query || {};
const token = query.token || '';
const filter = query.filter || 'all';
const sort = query.sort || 'alerte';

return [{ json: { token, filter, sort, timestamp: new Date().toISOString() } }];

const baseUrl = $('Webhook Stock List').first().json.headers?.host || 'localhost';
const currentUrl = `https://${baseUrl}/webhook/stock-list?token=`;
const loginUrl = `https://${baseUrl}/webhook/login?redirect_url=${encodeURIComponent(currentUrl)}`;
return [{ json: { redirect_url: loginUrl } }];

const token = $json.token;
const validToken = $env.STOCK_WEBHOOK_TOKEN || 'ABC';
if (token !== validToken) {
  return [{ json: { ...($json), valid: false } }];
}
return [{ json: { ...($json), valid: true } }];

const items = $input.all();
const params = $('Parse Params').first().json;
const token = params.token;

const stocks = items
  .filter(item => item.json?.id)
  .map(item => {
    const f = item.json.fields || {};
    const qte = f.QuantiteDisponible ?? 0;
    const seuil = f.SeuilMin ?? 2;
    const designation = f.Designation?.[0] || f.Designation || 'N/A';
    const categorie = f.Categorie?.[0] || f.Categorie || 'N/A';
    const emplacement = f.Emplacement || 'N/A';
    const dernierMvt = f.DernierMvt ? new Date(f.DernierMvt).toLocaleString('fr-FR') : 'N/A';
    const fournisseur = f.Fournisseur?.[0] || 'N/A';
    let statusClass, statusLabel;
    if (qte === 0) { statusClass = 'rupture'; statusLabel = '🔴 RUPTURE'; }
    else if (qte < seuil) { statusClass = 'bas'; statusLabel = '🟡 BAS'; }
    else { statusClass = 'ok'; statusLabel = '✅ OK'; }
    return {
      id: item.json.id,
      designation, categorie, emplacement, fournisseur,
      qte, seuil, dernierMvt, statusClass, statusLabel
    };
  });

const nbRuptures = stocks.filter(s => s.statusClass === 'rupture').length;
const nbBas = stocks.filter(s => s.statusClass === 'bas').length;
const nbOk = stocks.filter(s => s.statusClass === 'ok').length;
const now = new Date().toLocaleString('fr-FR', { timeZone: 'Europe/Paris' });

// Build HTML rows
const rows = stocks.map(s => `
  <tr class="row-${s.statusClass}" data-emplacement="${s.emplacement}">
    <td class="td-status"><span class="badge badge-${s.statusClass}">${s.statusLabel}</span></td>
    <td class="td-prod">
      <div class="prod-name">${s.designation}</div>
      <div class="prod-cat">${s.categorie}</div>
    </td>
    <td class="td-stock">
      <span class="stock-num stock-${s.statusClass}">${s.qte}</span>
      <span class="stock-seuil">/ ${s.seuil}</span>
    </td>
    <td class="td-empl">
      <span class="empl-badge empl-${s.emplacement.toLowerCase()}">${s.emplacement}</span>
    </td>
    <td class="td-mvt">${s.dernierMvt}</td>
    <td class="td-actions">
      <button class="btn-mvt btn-dec" onclick="mvt('${s.id}','${token}','decrement')" title="Décrémenter">−</button>
      <button class="btn-mvt btn-inc" onclick="mvt('${s.id}','${token}','increment')" title="Incrémenter">+</button>
    </td>
  </tr>`).join('');

const html = `<!DOCTYPE html>
<html lang="fr">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0, maximum-scale=1.0">
<meta name="theme-color" content="#1a1a2e">
<title>📦 Stocks Volets — Mon Usine</title>
<style>
  :root {
    --bg: #0f0f1a;
    --surface: #1a1a2e;
    --surface2: #252540;
    --text: #e2e8f0;
    --text-muted: #94a3b8;
    --accent: #6366f1;
    --ok: #22c55e;
    --bas: #f59e0b;
    --rupture: #ef4444;
    --border: rgba(255,255,255,0.08);
    --radius: 12px;
    --shadow: 0 4px 24px rgba(0,0,0,0.4);
  }
  * { box-sizing: border-box; margin: 0; padding: 0; }
  body {
    font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', system-ui, sans-serif;
    background: var(--bg);
    color: var(--text);
    min-height: 100vh;
    font-size: 14px;
  }
  .header {
    background: linear-gradient(135deg, var(--accent) 0%, #8b5cf6 100%);
    padding: 16px 20px;
    position: sticky;
    top: 0;
    z-index: 100;
    box-shadow: var(--shadow);
  }
  .header-inner {
    max-width: 900px;
    margin: 0 auto;
    display: flex;
    align-items: center;
    justify-content: space-between;
    flex-wrap: wrap;
    gap: 8px;
  }
  .header-title { font-size: 18px; font-weight: 700; }
  .header-sub { font-size: 12px; opacity: 0.8; }
  .stats-bar {
    background: var(--surface);
    border-bottom: 1px solid var(--border);
    padding: 12px 20px;
    position: sticky;
    top: 56px;
    z-index: 99;
  }
  .stats-inner {
    max-width: 900px;
    margin: 0 auto;
    display: flex;
    gap: 12px;
    flex-wrap: wrap;
    align-items: center;
  }
  .stat-chip {
    display: flex;
    align-items: center;
    gap: 6px;
    background: var(--surface2);
    border-radius: 20px;
    padding: 6px 14px;
    font-size: 13px;
    font-weight: 600;
    border: 1px solid var(--border);
  }
  .stat-chip.stat-ok { border-color: var(--ok); color: var(--ok); }
  .stat-chip.stat-bas { border-color: var(--bas); color: var(--bas); }
  .stat-chip.stat-rupture { border-color: var(--rupture); color: var(--rupture); }
  .filter-bar {
    max-width: 900px;
    margin: 16px auto 0;
    display: flex;
    gap: 8px;
    flex-wrap: wrap;
    padding: 0 20px;
  }
  .filter-btn {
    background: var(--surface2);
    color: var(--text-muted);
    border: 1px solid var(--border);
    border-radius: 8px;
    padding: 6px 14px;
    font-size: 12px;
    cursor: pointer;
    transition: all 0.2s;
  }
  .filter-btn.active {
    background: var(--accent);
    color: #fff;
    border-color: var(--accent);
  }
  .main { max-width: 900px; margin: 16px auto; padding: 0 12px 80px; }
  .table-wrap {
    background: var(--surface);
    border-radius: var(--radius);
    border: 1px solid var(--border);
    overflow: hidden;
    box-shadow: var(--shadow);
    overflow-x: auto;
  }
  table { width: 100%; border-collapse: collapse; }
  th {
    background: var(--surface2);
    color: var(--text-muted);
    font-size: 11px;
    font-weight: 600;
    text-transform: uppercase;
    letter-spacing: 0.5px;
    padding: 12px 16px;
    text-align: left;
    border-bottom: 1px solid var(--border);
  }
  tr {
    border-bottom: 1px solid var(--border);
    transition: background 0.15s;
  }
  tr:hover { background: rgba(255,255,255,0.03); }
  tr:last-child { border-bottom: none; }
  td { padding: 12px 16px; vertical-align: middle; }
  .row-rupture { border-left: 3px solid var(--rupture); }
  .row-bas { border-left: 3px solid var(--bas); }
  .row-ok { border-left: 3px solid var(--ok); }
  .badge {
    display: inline-block;
    padding: 3px 10px;
    border-radius: 12px;
    font-size: 11px;
    font-weight: 700;
    white-space: nowrap;
  }
  .badge-ok { background: rgba(34,197,94,0.15); color: var(--ok); }
  .badge-bas { background: rgba(245,158,11,0.15); color: var(--bas); }
  .badge-rupture { background: rgba(239,68,68,0.15); color: var(--rupture); }
  .prod-name { font-weight: 600; font-size: 13px; }
  .prod-cat { font-size: 11px; color: var(--text-muted); margin-top: 2px; }
  .stock-num { font-size: 20px; font-weight: 800; }
  .stock-ok { color: var(--ok); }
  .stock-bas { color: var(--bas); }
  .stock-rupture { color: var(--rupture); }
  .stock-seuil { font-size: 11px; color: var(--text-muted); margin-left: 4px; }
  .empl-badge {
    font-size: 11px;
    padding: 2px 8px;
    border-radius: 6px;
    background: var(--surface2);
    color: var(--text-muted);
  }
  .empl-atelier { background: rgba(99,102,241,0.15); color: #a5b4fc; }
  .empl-magasin { background: rgba(34,197,94,0.1); color: #86efac; }
  .empl-fournisseur { background: rgba(245,158,11,0.1); color: #fcd34d; }
  .td-mvt { font-size: 11px; color: var(--text-muted); white-space: nowrap; }
  .btn-mvt {
    width: 32px;
    height: 32px;
    border-radius: 8px;
    border: none;
    font-size: 18px;
    font-weight: 700;
    cursor: pointer;
    transition: transform 0.15s, opacity 0.15s;
    margin: 0 2px;
  }
  .btn-mvt:active { transform: scale(0.92); }
  .btn-dec { background: rgba(239,68,68,0.15); color: var(--rupture); }
  .btn-inc { background: rgba(34,197,94,0.15); color: var(--ok); }
  .empty-state {
    text-align: center;
    padding: 48px 20px;
    color: var(--text-muted);
  }
  .empty-state .icon { font-size: 48px; }
  .toast {
    position: fixed;
    bottom: 24px;
    left: 50%;
    transform: translateX(-50%) translateY(100px);
    background: var(--surface2);
    color: var(--text);
    padding: 12px 24px;
    border-radius: 12px;
    box-shadow: var(--shadow);
    border: 1px solid var(--border);
    z-index: 999;
    font-weight: 600;
    transition: transform 0.3s cubic-bezier(0.34,1.56,0.64,1);
    max-width: 320px;
    text-align: center;
  }
  .toast.show { transform: translateX(-50%) translateY(0); }
  .toast.toast-ok { border-color: var(--ok); }
  .toast.toast-err { border-color: var(--rupture); }
  .fab {
    position: fixed;
    bottom: 24px;
    right: 24px;
    background: var(--accent);
    color: #fff;
    border: none;
    width: 56px;
    height: 56px;
    border-radius: 50%;
    font-size: 22px;
    cursor: pointer;
    box-shadow: 0 4px 16px rgba(99,102,241,0.5);
    z-index: 200;
    display: flex;
    align-items: center;
    justify-content: center;
  }
  .refresh-time { font-size: 11px; color: var(--text-muted); }
  @media (max-width: 600px) {
    .th-mvt, .td-mvt-label { display: none; }
    .td-mvt { font-size: 10px; }
    th, td { padding: 10px 8px; }
    .prod-name { font-size: 12px; }
    .stock-num { font-size: 18px; }
  }
  .no-stocks {
    background: var(--surface);
    border-radius: var(--radius);
    padding: 48px;
    text-align: center;
    color: var(--ok);
    font-size: 16px;
    font-weight: 600;
  }
</style>
</head>
<body>
<div class="header">
  <div class="header-inner">
    <div>
      <div class="header-title">📦 Stocks Volets Roulants</div>
      <div class="header-sub">Mon Usine — Gestion Inventaire</div>
    </div>
    <div class="refresh-time">Màj: ${now}</div>
  </div>
</div>

<div class="stats-bar">
  <div class="stats-inner">
    <div class="stat-chip stat-rupture">🔴 ${nbRuptures} rupture(s)</div>
    <div class="stat-chip stat-bas">🟡 ${nbBas} stock(s) bas</div>
    <div class="stat-chip stat-ok">✅ ${nbOk} OK</div>
    <span style="margin-left:auto;font-size:12px;color:var(--text-muted)">${stocks.length} produits</span>
  </div>
</div>

<div class="filter-bar">
  <button class="filter-btn active" onclick="filterStocks('all',this)">Tous</button>
  <button class="filter-btn" onclick="filterStocks('Atelier',this)">🔧 Atelier</button>
  <button class="filter-btn" onclick="filterStocks('Magasin',this)">🏪 Magasin</button>
  <button class="filter-btn" onclick="filterStocks('Fournisseur',this)">🚚 Fournisseur</button>
  <button class="filter-btn" onclick="filterStocks('alert',this)">⚠️ Alertes</button>
</div>

<div class="main">
${stocks.length === 0 ? '<div class="no-stocks">✅ Aucun stock volet roulant enregistré.<br><small>Créez des enregistrements dans la table Stocks Airtable.</small></div>' : `
  <div class="table-wrap">
    <table id="stockTable">
      <thead>
        <tr>
          <th>Statut</th>
          <th>Désignation</th>
          <th>Stock / Seuil</th>
          <th>Emplacement</th>
          <th class="td-mvt-label">Dernier Mvt</th>
          <th>Actions</th>
        </tr>
      </thead>
      <tbody id="stockBody">
        ${rows}
      </tbody>
    </table>
  </div>`}
</div>

<button class="fab" onclick="location.reload()" title="Actualiser">🔄</button>
<div class="toast" id="toast"></div>

<script>
const TOKEN = '${token}';
const BASE_URL = window.location.origin + '/webhook/stock-scan';

function showToast(msg, type='ok') {
  const t = document.getElementById('toast');
  t.textContent = msg;
  t.className = 'toast show toast-' + type;
  setTimeout(() => { t.classList.remove('show'); }, 3500);
}

async function mvt(recordId, token, action) {
  const btn = event.target;
  btn.disabled = true;
  btn.style.opacity = '0.5';
  try {
    const url = BASE_URL + '?bonid=' + encodeURIComponent(recordId) + '&token=' + token + '&action=' + action + '&qte=1&operateur=dashboard';
    const resp = await fetch(url, { method: 'POST' });
    const data = await resp.json();
    if (data.success) {
      showToast((action==='decrement'?'\u2212':'+')+' 1 — Stock: ' + data.stock_apres + (data.stock_bas?' ⚠️ BAS':''), data.stock_bas?'err':'ok');
      setTimeout(() => location.reload(), 1500);
    } else {
      showToast('Erreur: ' + (data.error || 'Inconnu'), 'err');
    }
  } catch(e) {
    showToast('Erreur réseau', 'err');
  } finally {
    btn.disabled = false;
    btn.style.opacity = '1';
  }
}

function filterStocks(val, btn) {
  document.querySelectorAll('.filter-btn').forEach(b => b.classList.remove('active'));
  btn.classList.add('active');
  const rows = document.querySelectorAll('#stockBody tr');
  rows.forEach(row => {
    if (val === 'all') {
      row.style.display = '';
    } else if (val === 'alert') {
      row.style.display = (row.classList.contains('row-rupture') || row.classList.contains('row-bas')) ? '' : 'none';
    } else {
      row.style.display = row.dataset.emplacement === val ? '' : 'none';
    }
  });
}

// Auto-refresh toutes les 5 minutes
setTimeout(() => location.reload(), 5 * 60 * 1000);
</script>
</body>
</html>`;

return [{ json: { html } }];
